import re
from dataclasses import dataclass

@dataclass
class FilterConfig:
    min_tokens: int = 20
    max_tokens: int = 2048
    max_word_repetition_ratio: float = 0.3  # fraction of top-1 word in response
    max_char_repetition_ngram: int = 4       # max repeated char n-gram count
    refusal_phrases: tuple = (
        "i cannot", "i'm unable", "i am unable", "as an ai",
        "i'm an ai", "i don't have personal",
    )
    min_response_to_instruction_ratio: float = 0.5


def heuristic_filter(instruction: str, response: str,
                      cfg: FilterConfig = FilterConfig()) -> tuple[bool, str]:
    """
    Returns (keep, reason). reason is empty string if keeping.
    """
    resp_words = response.lower().split()

    # Length check
    if len(resp_words) < cfg.min_tokens:
        return False, f"too_short({len(resp_words)})"
    if len(resp_words) > cfg.max_tokens:
        return False, f"too_long({len(resp_words)})"

    # Word repetition: top word should not dominate
    if resp_words:
        from collections import Counter
        top_count = Counter(resp_words).most_common(1)[0][1]
        ratio = top_count / len(resp_words)
        if ratio > cfg.max_word_repetition_ratio:
            return False, f"word_repetition({ratio:.2f})"

    # Character n-gram repetition (catches "aaaaaa..." degenerate outputs)
    for n in [4, 8]:
        ngrams = [response[i:i+n] for i in range(len(response)-n+1)]
        if ngrams:
            from collections import Counter
            max_count = Counter(ngrams).most_common(1)[0][1]
            if max_count > cfg.max_char_repetition_ngram:
                return False, f"char_ngram_repeat(n={n}, count={max_count})"

    # Refusal check
    resp_lower = response.lower()
    for phrase in cfg.refusal_phrases:
        if phrase in resp_lower:
            return False, f"refusal('{phrase}')"

    # Response must not be shorter than instruction by a large margin
    inst_words = len(instruction.split())
    if inst_words > 0 and len(resp_words) / inst_words < cfg.min_response_to_instruction_ratio:
        return False, "response_too_short_vs_instruction"

    return True, ""


def apply_heuristic_filters(dataset: list[dict],
                              cfg: FilterConfig = FilterConfig()) -> tuple[list, dict]:
    kept, dropped = [], {}
    for item in dataset:
        keep, reason = heuristic_filter(
            item.get('instruction', item.get('prompt', '')),
            item.get('output', item.get('response', '')),
            cfg
        )
        if keep:
            kept.append(item)
        else:
            dropped[reason] = dropped.get(reason, 0) + 1
    return kept, dropped

import re
from datasets import load_dataset

def extract_ngrams(text: str, n: int = 13) -> set[str]:
    """Extract all n-grams (character-level) from text."""
    text = re.sub(r'\s+', ' ', text.lower().strip())
    return {text[i:i+n] for i in range(len(text)-n+1)}


def load_benchmark_ngrams(benchmarks: list[str], n: int = 13) -> set[str]:
    """Build a set of n-grams from all benchmark test questions."""
    all_ngrams = set()
    for name in benchmarks:
        try:
            # Load the test split only — never the train split
            ds = load_dataset(name, split='test')
            text_fields = ['question', 'text', 'sentence', 'premise']
            for item in ds:
                for field in text_fields:
                    if field in item and item[field]:
                        all_ngrams |= extract_ngrams(str(item[field]), n=n)
        except Exception as e:
            print(f"Skipping {name}: {e}")
    return all_ngrams


def contamination_filter(dataset: list[dict],
                           benchmark_ngrams: set[str],
                           field: str = 'instruction',
                           n: int = 13,
                           min_overlap: int = 1) -> list[dict]:
    """Remove examples with ≥ min_overlap matching n-grams in benchmarks."""
    clean = []
    for item in dataset:
        text   = item.get(field, '')
        ngrams = extract_ngrams(text, n=n)
        if len(ngrams & benchmark_ngrams) < min_overlap:
            clean.append(item)
    return clean

# Example usage
BENCHMARKS = ['gsm8k', 'allenai/arc', 'hellaswag', 'Muennighoff/mmlu']
bench_ngrams = load_benchmark_ngrams(BENCHMARKS, n=13)
